t emit = defineEmits<{\n  close: [];\n  openPanel: [];\n}>();\n\nconst store = useStore();\nconst menuRef = ref<HTMLElement>();\n\nconst MENU_WIDTH = 320;\nconst MENU_MAX_HEIGHT = 480;\nconst MARGIN = 12;\n\nconst menuStyle = computed(() => {\n  // 获取可视区域\n  let vw = window.innerWidth;\n  let vh = window.innerHeight;\n  try {\n    if (window.parent && window.parent !== window) {\n      vw = window.parent.innerWidth;\n      vh = window.parent.innerHeight;\n    }\n  } catch { /* 跨域静默 */ }\n\n  const ballCenterX = props.ballX + props.ballSize / 2;\n  const ballCenterY = props.ballY + props.ballSize / 2;\n\n  // 水平位置：优先在球的左边，空间不够则放右边\n  let left: number;\n  if (ballCenterX > vw / 2) {\n    // 球在右半边 → 菜单在球左边\n    left = props.ballX - MENU_WIDTH - MARGIN;\n  } else {\n    // 球在左半边 → 菜单在球右边\n    left = props.ballX + props.ballSize + MARGIN;\n  }\n\n  // 垂直位置：对齐球的中心\n  let top = ballCenterY - MENU_MAX_HEIGHT / 2;\n\n  // 边界约束\n  if (left < MARGIN) left = MARGIN;\n  if (left + MENU_WIDTH > vw - MARGIN) left = vw - MENU_WIDTH - MARGIN;\n  if (top < MARGIN) top = MARGIN;\n  if (top + MENU_MAX_HEIGHT > vh - MARGIN) top = vh - MENU_MAX_HEIGHT - MARGIN;\n\n  return {\n    left: `${left}px`,\n    top: `${top}px`,\n    width: `${MENU_WIDTH}px`,\n    maxHeight: `${MENU_MAX_HEIGHT}px`,\n  };\n});\n</script>\n\n<style scoped>\n.bm-backdrop {\n  position: fixed;\n  inset: 0;\n  z-index: 99998;\n  pointer-events: auto;\n}\n\n.bm-menu {\n  position: fixed;\n  z-index: 99999;\n  pointer-events: auto;\n  display: flex;\n  flex-direction: column;\n  border-radius: 14px;\n  overflow: hidden;\n  background: rgba(22, 22, 30, 0.94);\n  backdrop-filter: blur(20px) saturate(180%);\n  -webkit-backdrop-filter: blur(20px) saturate(180%);\n  border: 1px solid rgba(255, 255, 255, 0.1);\n  box-shadow:\n    0 12px 40px rgba(0, 0, 0, 0.55),\n    0 0 0 1px rgba(255, 255, 255, 0.04) inset;\n  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', 'Noto Sans SC', sans-serif;\n  color: rgba(255, 255, 255, 0.88);\n  animation: bm-fade-in 0.18s ease-out;\n}\n\n@keyframes bm-fade-in {\n  from {\n    opacity: 0;\n    transform: scale(0.92) translateY(8px);\n  }\n  to {\n    opacity: 1;\n    transform: scale(1) translateY(0);\n  }\n}\n\n.bm-header {\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  padding: 10px 14px;\n  background: rgba(255, 255, 255, 0.03);\n  border-bottom: 1px solid rgba(255, 255, 255, 0.06);\n  flex-shrink: 0;\n}\n\n.bm-title {\n  font-size: 13px;\n  font-weight: 600;\n  color: rgba(255, 255, 255, 0.85);\n  letter-spacing: 0.3px;\n}\n\n.bm-header-actions {\n  display: flex;\n  gap: 2px;\n}\n\n.bm-header-btn {\n  width: 26px;\n  height: 26px;\n  border: none;\n  border-radius: 6px;\n  background: transparent;\n  color: rgba(255, 255, 255, 0.4);\n  cursor: pointer;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  font-size: 12px;\n  transition: background 0.15s, color 0.15s;\n}\n\n.bm-header-btn:hover {\n  background: rgba(255, 255, 255, 0.08);\n  color: rgba(255, 255, 255, 0.8);\n}\n\n.bm-body {\n  flex: 1;\n  overflow-y: auto;\n  padding: 12px;\n  display: flex;\n  flex-direction: column;\n}\n\n/* 自定义滚动条 */\n.bm-body::-webkit-scrollbar {\n  width: 4px;\n}\n\n.bm-body::-webkit-scrollbar-track {\n  background: transparent;\n}\n\n.bm-body::-webkit-scrollbar-thumb {\n  background: rgba(255, 255, 255, 0.1);\n  border-radius: 2px;\n}\n\n.bm-body::-webkit-scrollbar-thumb:hover {\n  background: rgba(255, 255, 255, 0.2);\n}\n</style>\n"],"sourceRoot":""}]);
