`, "",{"version":3,"sources":["webpack://./src/ST-BarTender/FloatingBall.vue"],"names":[],"mappings":"AA4IA,0BACE,cAAe,CACf,aAAc,CACd,mBAAoB,CACpB,OACF,CAEA,0BACE,cAAe,CACf,mBAAoB,CACpB,iBAAkB,CAClB,YAAa,CACb,kBAAmB,CACnB,sBAAuB,CACvB,WAAY,CACZ,wBAAiB,CAAjB,gBAAiB,CACjB,cAAe,CACf,4BAAgC,CAChC,8BAAkC,CAClC,yCAA0C,CAC1C,iDAAkD,CAClD,uCAA2C,CAC3C,4EAE2C,CAC3C,2DACF,CAEA,gCACE,8BAAkC,CAClC,4GAGoC,CACpC,qBACF,CAEA,iCACE,eAAgB,CAChB,qBACF,CAEA,kCACE,gCAAoC,CACpC,mCAAuC,CACvC,oEAEmC,CACnC,aACF","sourcesContent":["<template>\n  <div class=\"fb-root\">\n    <!-- 悬浮球 -->\n    <div\n      ref=\"ballRef\"\n      class=\"fb-ball\"\n      :class=\"{ 'fb-ball--active': store.ballMenuOpen }\"\n      :style=\"ballStyle\"\n      @mousedown.prevent=\"onMouseDown\"\n    >\n      <i class=\"fa-solid fa-sliders\" />\n    </div>\n\n    <!-- 气泡菜单 -->\n    <BubbleMenu\n      v-if=\"store.ballMenuOpen\"\n      :ball-x=\"ballPos.x\"\n      :ball-y=\"ballPos.y\"\n      :ball-size=\"BALL_SIZE\"\n      @close=\"store.ballMenuOpen = false\"\n      @open-panel=\"openMainPanel\"\n    />\n  </div>\n</template>\n\n<script setup lang=\"ts\">\nimport { useStore } from './store';\nimport BubbleMenu from './BubbleMenu.vue';\n\nconst store = useStore();\n\nconst BALL_SIZE = 48;\nconst CLICK_THRESHOLD = 5; // 拖拽判定阈值（像素）\n\n// ---------- 位置状态 ----------\nconst ballPos = ref({\n  x: store.settings.ball_x >= 0 ? store.settings.ball_x : -1,\n  y: store.settings.ball_y >= 0 ? store.settings.ball_y : -1,\n});\n\nconst ballStyle = computed(() => ({\n  left: `${ballPos.value.x}px`,\n  top: `${ballPos.value.y}px`,\n  width: `${BALL_SIZE}px`,\n  height: `${BALL_SIZE}px`,\n}));\n\n// ---------- 拖拽逻辑 ----------\nconst ballRef = ref<HTMLElement>();\nconst isDragging = ref(false);\nconst hasMoved = ref(false);\nconst startPos = { x: 0, y: 0 };\nconst dragOffset = { x: 0, y: 0 };\n\nfunction onMouseDown(e: MouseEvent) {\n  isDragging.value = true;\n  hasMoved.value = false;\n  startPos.x = e.clientX;\n  startPos.y = e.clientY;\n  dragOffset.x = e.clientX - ballPos.value.x;\n  dragOffset.y = e.clientY - ballPos.value.y;\n\n  document.addEventListener('mousemove', onMouseMove);\n  document.addEventListener('mouseup', onMouseUp);\n  try {\n    window.parent?.document?.addEventListener('mousemove', onMouseMove);\n    window.parent?.document?.addEventListener('mouseup', onMouseUp);\n  } catch { /* 跨域静默 */ }\n}\n\nfunction onMouseMove(e: MouseEvent) {\n  if (!isDragging.value) return;\n\n  // 用起始位置判断是否真的拖拽了\n  const dx = Math.abs(e.clientX - startPos.x);\n  const dy = Math.abs(e.clientY - startPos.y);\n  if (!hasMoved.value && dx + dy > CLICK_THRESHOLD) {\n    hasMoved.value = true;\n  }\n\n  if (hasMoved.value) {\n    ballPos.value.x = e.clientX - dragOffset.x;\n    ballPos.value.y = e.clientY - dragOffset.y;\n  }\n}\n\nfunction onMouseUp() {\n  isDragging.value = false;\n  cleanupDragListeners();\n\n  if (hasMoved.value) {\n    // 拖拽结束：保存位置\n    store.settings.ball_x = ballPos.value.x;\n    store.settings.ball_y = ballPos.value.y;\n  } else {\n    // 点击：切换菜单\n    store.toggleBallMenu();\n  }\n}\n\nfunction cleanupDragListeners() {\n  document.removeEventListener('mousemove', onMouseMove);\n  document.removeEventListener('mouseup', onMouseUp);\n  try {\n    window.parent?.document?.removeEventListener('mousemove', onMouseMove);\n    window.parent?.document?.removeEventListener('mouseup', onMouseUp);\n  } catch { /* 跨域静默 */ }\n}\n\n// ---------- 打开主面板 ----------\nfunction openMainPanel() {\n  store.ballMenuOpen = false;\n  store.panelOpen = true;\n}\n\n// ---------- 初始位置 ----------\nonMounted(() => {\n  if (ballPos.value.x < 0 || ballPos.value.y < 0) {\n    let w = window.innerWidth;\n    let h = window.innerHeight;\n    try {\n      if (window.parent && window.parent !== window) {\n        w = window.parent.innerWidth;\n        h = window.parent.innerHeight;\n      }\n    } catch { /* 跨域静默 */ }\n    ballPos.value.x = w - BALL_SIZE - 20;\n    ballPos.value.y = h / 2 - BALL_SIZE / 2;\n  }\n\n  // 首次加载时自动扫描预设生成基础界面\n  store.autoGenerateFromPreset();\n});\n\nonUnmounted(() => {\n  cleanupDragListeners();\n});\n</script>\n\n<style scoped>\n.fb-root {\n  position: fixed;\n  z-index: 99998;\n  pointer-events: none;\n  inset: 0;\n}\n\n.fb-ball {\n  position: fixed;\n  pointer-events: auto;\n  border-radius: 50%;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  cursor: grab;\n  user-select: none;\n  font-size: 18px;\n  color: rgba(255, 255, 255, 0.85);\n  background: rgba(30, 30, 42, 0.88);\n  backdrop-filter: blur(16px) saturate(180%);\n  -webkit-backdrop-filter: blur(16px) saturate(180%);\n  border: 1px solid rgba(255, 255, 255, 0.12);\n  box-shadow:\n    0 4px 20px rgba(0, 0, 0, 0.4),\n    0 0 0 1px rgba(255, 255, 255, 0.05) inset;\n  transition: box-shadow 0.25s, transform 0.2s, background 0.25s;\n}\n\n.fb-ball:hover {\n  background: rgba(38, 38, 52, 0.92);\n  box-shadow:\n    0 6px 28px rgba(0, 0, 0, 0.5),\n    0 0 0 1px rgba(255, 255, 255, 0.08) inset,\n    0 0 16px rgba(100, 181, 246, 0.15);\n  transform: scale(1.08);\n}\n\n.fb-ball:active {\n  cursor: grabbing;\n  transform: scale(0.95);\n}\n\n.fb-ball--active {\n  background: rgba(100, 181, 246, 0.2);\n  border-color: rgba(100, 181, 246, 0.35);\n  box-shadow:\n    0 4px 20px rgba(0, 0, 0, 0.4),\n    0 0 20px rgba(100, 181, 246, 0.2);\n  color: #64b5f6;\n}\n</style>\n"],"sourceRoot":""}]);
